insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'If today is Monday, what day will it be after 45 days?', 'यदि आज Monday है, तो 45 days बाद कौन सा day होगा?', '45 mod 7 = 3. Move 3 days from Monday; the day is Thursday. Therefore, answer = Thursday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Thursday.', '45 mod 7 = 3। Monday से 3 days आगे बढ़ें; day Thursday होगा। अतः answer = Thursday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Thursday है।', 'EASY', array['calendar','odd-days']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
