insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Saturday', 'Saturday', false, 'Reduced 45 by 7 incorrectly and moved two days too far.', '45 को 7 से गलत reduce किया और two days आगे चले गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Monday', 'Monday', false, 'Assumed the same day repeats without checking 45 mod 7. Same day occurs only if remainder is 0.', '45 mod 7 check किए बिना same day मान लिया। Same day तभी होगा जब remainder 0 हो।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'If today is Wednesday, what day will it be after 31 days?', 'यदि आज Wednesday है, तो 31 days बाद कौन सा day होगा?', '31 mod 7 = 3. Move 3 days from Wednesday; the day is Saturday. Therefore, answer = Saturday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Saturday.', '31 mod 7 = 3। Wednesday से 3 days आगे बढ़ें; day Saturday होगा। अतः answer = Saturday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Saturday है।', 'EASY', array['calendar','odd-days']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
