insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Friday', 'Friday', false, 'Moved one day backward due to excluding the target date.', 'Target date exclude करने से one day पीछे चले गए।');
